ToolUseBlock(id='toolu_01LaxaZ5KRv6HhURH7kwigKC', name='Write', input={'file_path': '/workspace/app/src/components/Breadcrumb.jsx', 'content': 'import { Link } from 'react-router-dom'

export default function Breadcrumb({ items = [] }) {
  // items: [{ label, to? }, ...]; last item is current page (no link)
  const full = [{ label: 'Home', to: '/' }, ...items]
  return (
    <nav className="breadcrumb" aria-label="Breadcrumb">
      <div className="container">
        <ol>
          {full.map((it, idx) => {
            const isLast = idx === full.length - 1
            return (
              <li key={idx} aria-current={isLast ? 'page' : undefined}>
                {!isLast && it.to ? <Link to={it.to}>{it.label}</Link> : <span>{it.label}</span>}
              </li>
            )
          })}
        </ol>
      </div>
    </nav>
  )
}
'})

ToolUseBlock(id='toolu_01Rn5zuaRqKLXf9TyfXss3yK', name='Write', input={'file_path': '/workspace/app/src/components/Pagination.jsx', 'content': 'export default function Pagination({ page, totalPages, onChange }) {
  if (totalPages <= 1) return null

  const buildPageList = () => {
    const pages = []
    const add = (p) => pages.push(p)
    const window = 1

    add(1)
    if (page - window > 2) add('…')
    for (let p = Math.max(2, page - window); p <= Math.min(totalPages - 1, page + window); p++) {
      add(p)
    }
    if (page + window < totalPages - 1) add('…')
    if (totalPages > 1) add(totalPages)
    return pages
  }

  const pages = buildPageList()
  const go = (p) => {
    if (p < 1 || p > totalPages || p === page) return
    onChange(p)
  }

  return (
    <nav className="pagination" aria-label="Pagination">
      <button onClick={() => go(page - 1)} disabled={page === 1} aria-label="Previous">‹ Prev</button>
      {pages.map((p, i) =>
        p === '…' ? (
          <span key={`e${i}`} className="ellipsis">…</span>
        ) : (
          <button
            key={p}
            onClick={() => go(p)}
            className={p === page ? 'active' : undefined}
            aria-current={p === page ? 'page' : undefined}
          >
            {p}
          </button>
        )
      )}
      <button onClick={() => go(page + 1)} disabled={page === totalPages} aria-label="Next">Next ›</button>
    </nav>
  )
}
'})

