      policyArea: POLICY_AREAS[pIdx],
      excerpt:
        'The FSB issued the following item as part of its ongoing work to promote global financial stability through monitoring and coordination.',
      date,
    })
  }
  out.sort((a, b) => b.date - a.date)
  return out
}

